{
  "name": "image-flow",
  "displayName": "Image Flow",
  "description": "在 VS Code 中调用 AI 绘图后端生成图片",
  "version": "1.0.0",
  "publisher": "image-flow",
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": [
    "Other"
  ],
  "activationEvents": [
    "onStartupFinished"
  ],
  "main": "./dist/extension.js",
  "contributes": {
    "viewsContainers": {
      "activitybar": [
        {
          "id": "image-flow",
          "title": "AI 绘图",
          "icon": "media/icon.svg"
        }
      ]
    },
    "views": {
      "image-flow": [
        {
          "type": "webview",
          "id": "image-flow.sidebar",
          "name": "AI 绘图"
        }
      ]
    },
    "commands": [
      {
        "command": "image-flow.generateImage",
        "title": "Image Flow: 生成 AI 图片"
      },
      {
        "command": "image-flow.previewRequest",
        "title": "Image Flow: 预览请求"
      }
    ],
    "menus": {
      "explorer/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ],
      "editor/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ]
    },
    "configuration": {
      "title": "Image Flow",
      "properties": {
        "image-flow.model": {
          "type": "string",
          "default": "nano-banana-2",
          "enum": [
            "nano-banana-2",
            "nano-banana-pro",
            "gpt-image-2",
            "gpt-image-2-vip"
          ],
          "description": "AI 绘图模型"
        },
        "image-flow.aspectRatio": {
          "type": "string",
          "default": "3:4",
          "enum": [
            "1:1",
            "16:9",
            "9:16",
            "4:3",
            "3:4"
          ],
          "description": "图片比例"
        },
        "image-flow.imageSize": {
          "type": "string",
          "default": "1K",
          "enum": [
            "1K",
            "2K",
            "4K"
          ],
          "description": "图片分辨率"
        },
        "image-flow.concurrency": {
          "type": "number",
          "default": 1,
          "minimum": 1,
          "maximum": 10,
          "description": "一次生成的并发张数"
        }
      }
    }
  },
  "scripts": {
    "compile": "npm run check-types && npm run lint && node esbuild.config.js",
    "watch": "node esbuild.config.js --watch",
    "package": "npm run check-types && npm run lint && node esbuild.config.js --production",
    "check-types": "tsc -p tsconfig.json --noEmit && tsc -p tsconfig.webview.json --noEmit",
    "lint": "eslint src/ test/ media/",
    "test": "tsc -p tsconfig.test.json && node ./out/test/runTest.js",
    "vscode:prepublish": "npm run package"
  },
  "devDependencies": {
    "@types/mocha": "^10.0.10",
    "@types/node": "^20.11.0",
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@types/vscode": "^1.85.0",
    "@vscode/test-cli": "^0.0.10",
    "@vscode/test-electron": "^2.4.0",
    "esbuild": "^0.24.0",
    "eslint": "^9.0.0",
    "typescript": "^5.7.0",
    "typescript-eslint": "^8.0.0"
  },
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "@radix-ui/react-tabs": "^1.1.0",
    "@radix-ui/react-select": "^2.1.0",
    "@radix-ui/react-scroll-area": "^1.2.0",
    "@radix-ui/react-collapsible": "^1.1.0"
  }
}

const esbuild = require('esbuild');

const isWatch = process.argv.includes('--watch');
const isProduction = process.argv.includes('--production');

/** @type {esbuild.BuildOptions} */
const extensionConfig = {
  entryPoints: ['src/extension.ts'],
  bundle: true,
  outfile: 'dist/extension.js',
  external: ['vscode'],
  format: 'cjs',
  platform: 'node',
  target: 'node18',
  sourcemap: !isProduction,
  minify: isProduction,
  metafile: true,
};

/** @type {esbuild.BuildOptions} */
const sidebarConfig = {
  entryPoints: ['media/sidebar.tsx'],
  bundle: true,
  outfile: 'media/sidebar.js',
  format: 'iife',
  platform: 'browser',
  target: 'es2020',
  sourcemap: !isProduction,
  minify: isProduction,
  metafile: true,
  define: {
    'process.env.NODE_ENV': isProduction ? '"production"' : '"development"',
  },
};

async function build() {
  try {
    const [extResult, sidebarResult] = await Promise.all([
      esbuild.build(extensionConfig),
      esbuild.build(sidebarConfig),
    ]);

    if (!isWatch) {
      const extText = await esbuild.analyzeMetafile(extResult.metafile);
      console.log('Extension bundle analysis:\n', extText);
      const sidebarText = await esbuild.analyzeMetafile(sidebarResult.metafile);
      console.log('Sidebar bundle analysis:\n', sidebarText);
    }
  } catch (err) {
    console.error('Build failed:', err);
    process.exit(1);
  }
}

if (isWatch) {
  const ctx = esbuild.context({
    ...extensionConfig,
    plugins: [],
  });
  // Watch mode handled via separate contexts
  console.log('Watch mode not yet implemented for dual builds');
  build();
} else {
  build();
}

const tseslint = require('typescript-eslint');

module.exports = tseslint.config(
  {
    ignores: ['dist/**', 'out/**', 'node_modules/**', 'media/sidebar.js'],
  },
  {
    files: ['**/*.ts', '**/*.tsx'],
    languageOptions: {
      parser: tseslint.parser,
      parserOptions: {
        project: ['./tsconfig.json', './tsconfig.webview.json', './tsconfig.test.json'],
      },
    },
    plugins: {
      '@typescript-eslint': tseslint.plugin,
    },
    rules: {
      '@typescript-eslint/no-unused-vars': ['warn', { argsIgnorePattern: '^_' }],
      '@typescript-eslint/no-explicit-any': 'warn',
      '@typescript-eslint/explicit-function-return-type': 'off',
      'no-console': 'off',
    },
  }
);

{
  "version": "0.2.0",
  "configurations": [
    {
      "name": "Run Extension",
      "type": "extensionHost",
      "request": "launch",
      "args": [
        "--extensionDevelopmentPath=${workspaceFolder}"
      ],
      "outFiles": [
        "${workspaceFolder}/dist/**/*.js"
      ],
      "preLaunchTask": "npm: compile"
    }
  ]
}

