    }
  } catch { /* skip */ }
}

/** 生成自动素材库：从工作区根下一层到 MD 目录为止，每层取直接图片 */
export function getAutoAssetFolders(workspaceRoot: string, mdPath: string): AssetFolder[] {
  if (!workspaceRoot || !mdPath || !mdPath.startsWith(workspaceRoot)) { return []; }

  const mdDir = path.dirname(mdPath);
  const folders: AssetFolder[] = [];

  // 从工作区根下一层起，到 MD 目录为止
  let current = mdDir;
  while (current !== workspaceRoot && current !== path.dirname(current)) {
    const layerName = path.relative(workspaceRoot, current);
    if (layerName === '') { break; }

    const images = scanDirectImages(current);
    if (images.length > 0) {
      folders.push({
        name: layerName,
        path: current,
        auto: true,
        images,
      });
    }
    current = path.dirname(current);
  }

  // 保持从工作区向 MD 目录方向排序
  folders.reverse();
  return folders;
}

/** 扫描目录下直接的图片文件（不递归） */
function scanDirectImages(dir: string): string[] {
  const images: string[] = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isFile()) {
        const fullPath = path.join(dir, entry.name);
        if (isImageFile(fullPath)) {
          images.push(fullPath);
        }
      }
    }
  } catch { /* skip */ }
  return images.sort();
}

/** 获取手动素材库列表（含扫描结果） */
export function getManualAssetFolders(folderPaths: string[]): AssetFolder[] {
  return folderPaths.map(fp => ({
    name: path.basename(fp),
    path: fp,
    auto: false,
    images: scanAssetFolder(fp),
  }));
}

/** 全部素材库（自动 + 手动） */
export function getAllAssetFolders(
  workspaceRoot: string,
  mdPath: string,
  manualFolders: string[],
): AssetFolder[] {
  const auto = getAutoAssetFolders(workspaceRoot, mdPath);
  const manual = getManualAssetFolders(manualFolders);
  return [...auto, ...manual];
}

/** 生成插入引用的相对路径（POSIX 风格） */
export function buildInsertRef(imagePath: string, mdPath: string): string | null {
  try {
    let rel = path.relative(path.dirname(mdPath), imagePath);
    // 转为 POSIX 风格
    rel = rel.replace(/\\/g, '/');

    // 跨盘符检查
    if (rel.startsWith('..') && rel.includes(':')) {
      return null; // 跨盘符无法相对引用
    }

    // 非 .. 开头加 ./ 前缀
    if (!rel.startsWith('.')) {
      rel = './' + rel;
    }

    const alt = path.basename(imagePath, path.extname(imagePath));

    // 含空格或半角括号用 <> 包裹
    if (/[ ()]/.test(rel)) {
      return `![${alt}](<${rel}>)`;
    }
    return `![${alt}](${rel})`;
  } catch {
    return null;
  }
}

// 预览请求：构造与真实请求一致的预览文档
import * as path from 'path';
import { VIP_PIXEL_TABLE, isNanoBananaModel, isGptImage2Vip } from './utils';

export interface PreviewParts {
  prompt: string;
  url: string;
  params: string;
  referenceOverview: string;
}

/**
 * 组装完整预览内容
 * @param model 模型
 * @param aspectRatio 比例
 * @param imageSize 分辨率
 * @param baseUrl 节点地址
 * @param finalPrompt 最终提示词（含注入）
 * @param referenceDataUris 参考图 data URI 数组
 * @param referenceFileNames 参考图文件名数组（与 dataUris 对应）
 * @returns 预览文本
 */
export function buildPreview(
  model: string,
  aspectRatio: string,
  imageSize: string,
  baseUrl: string,
  finalPrompt: string,
  referenceDataUris: string[],
  referenceFileNames: string[],
): string {
  // 构建请求体（不含 prompt 和 images 字段）
  const reqBody: Record<string, unknown> = {
    model,
    replyType: 'async',
  };

  if (isNanoBananaModel(model)) {
    reqBody.aspectRatio = aspectRatio;
    reqBody.imageSize = imageSize;
  } else if (isGptImage2Vip(model)) {
    reqBody.aspectRatio = VIP_PIXEL_TABLE[aspectRatio]?.[imageSize] ?? aspectRatio;
  } else {
    // gpt-image-2
    reqBody.aspectRatio = aspectRatio;
  }

  // 参考图概览
  let refOverview: string;
  if (referenceDataUris.length === 0) {
    refOverview = '无参考图';
  } else {
    refOverview = referenceFileNames
      .map((name, i) => {
        const uri = referenceDataUris[i] ?? '';
        const preview = uri.length > 48 ? uri.slice(0, 48) + '…' : uri;
        return `image${i + 1}: ${preview}（${uri.length} 字符）`;
      })
      .join('\n');
  }

  const url = `POST ${baseUrl}/v1/api/generate`;

  return [
    finalPrompt,
    url,
    JSON.stringify(reqBody, null, 2),
    refOverview,
  ].join('\n\n---\n\n');
}

