  display: flex;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.tab-btn {
  flex: 1;
  padding: 8px 12px;
  border: none;
  background: transparent;
  color: var(--fg);
  cursor: pointer;
  font-size: 13px;
  border-bottom: 2px solid transparent;
  transition: background 0.15s;
}

.tab-btn:hover {
