  flex: 1;
  overflow-y: auto;
  padding: 8px;
}

/* Workbench */
.workbench-tab {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.asset-section {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

.asset-folder {
  margin-bottom: 8px;
}

.asset-folder-header {
  display: flex;
