  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--vscode-descriptionForeground, #999);
}

/* Buttons */
.btn {
  padding: 4px 12px;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  font-size: 12px;
  white-space: nowrap;
}

.btn-primary {
  background: var(--btn-bg);
  color: var(--btn-fg);
}

.btn-primary:hover:not(:disabled) {
  background: var(--btn-hover);
}

.btn-primary:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-secondary {
  background: transparent;
  color: var(--fg);
  border: 1px solid var(--border);
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.1);
}

.btn-link {
  background: transparent;
  color: var(--accent);
  border: none;
  padding: 0;
  cursor: pointer;
  font-size: 12px;
  text-decoration: underline;
}

.icon-btn {
  background: transparent;
  border: none;
  color: var(--fg);
  cursor: pointer;
  font-size: 14px;
  padding: 0 4px;
  line-height: 1;
}

.icon-btn:hover {
  color: var(--error);
}

/* Status Line */
.status-line {
  font-size: 12px;
  min-height: 18px;
  line-height: 18px;
}

.status-line.error {
  color: var(--error);
}

.status-line.warning {
  color: var(--warning);
}

/* Tasks Tab */
.tasks-tab {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.empty-hint {
  text-align: center;
  color: var(--vscode-descriptionForeground, #999);
  padding: 24px 0;
}

/* Task Cards */
.task-card {
  border: 1px solid var(--border);
  border-radius: 4px;
  overflow: hidden;
}

.task-card.active {
  border-color: var(--accent);
}

.task-card-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px;
  cursor: pointer;
  user-select: none;
  background: rgba(255, 255, 255, 0.03);
}

.task-card-header:hover {
  background: rgba(255, 255, 255, 0.06);
}

.collapse-icon {
  font-size: 10px;
  width: 12px;
  text-align: center;
  flex-shrink: 0;
}

.task-title {
  font-size: 12px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.task-card-body {
  padding: 8px;
}

/* Progress Bar */
.progress-bar-container {
  height: 6px;
  background: var(--border);
  border-radius: 3px;
  margin-bottom: 8px;
  position: relative;
  overflow: hidden;
}

.progress-bar {
  height: 100%;
  background: var(--accent);
  border-radius: 3px;
  transition: width 0.3s;
}

.progress-text {
  position: absolute;
  right: 0;
  top: -16px;
  font-size: 11px;
  color: var(--vscode-descriptionForeground, #999);
}

.task-hint {
  font-size: 12px;
  color: var(--vscode-descriptionForeground, #999);
  margin-bottom: 4px;
}

.task-errors {
  margin-bottom: 8px;
}

.error-text {
  font-size: 12px;
  color: var(--error);
}

/* Task Image Grid */
.task-images-grid {
  display: grid;
  gap: 4px;
  margin-top: 8px;
}

.task-thumb {
  aspect-ratio: 1;
  overflow: hidden;
  border-radius: 4px;
  cursor: pointer;
  border: 2px solid transparent;
  transition: border-color 0.15s;
}

.task-thumb:hover {
  border-color: var(--accent);
}

.task-thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* Settings Tab */
.settings-tab {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.setting-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.setting-item label {
  font-size: 12px;
  font-weight: 600;
}

.setting-row {
  display: flex;
  gap: 6px;
  align-items: center;
}

.text-input {
  flex: 1;
  background: var(--input-bg);
  color: var(--input-fg);
  border: 1px solid var(--input-border);
  padding: 6px 8px;
  border-radius: 3px;
  font-size: 12px;
  outline: none;
  font-family: inherit;
}

.text-input:focus {
  border-color: var(--accent);
}

textarea.text-input {
  resize: vertical;
  min-height: 60px;
}

.mb-small {
  margin-bottom: 4px;
}

/* Context Menu */
.context-menu {
  position: fixed;
  z-index: 1000;
  background: var(--vscode-menu-background, #252526);
  border: 1px solid var(--vscode-menu-border, #454545);
  border-radius: 4px;
  padding: 4px 0;
  min-width: 180px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.context-menu button {
  display: block;
  width: 100%;
  padding: 4px 12px;
  border: none;
  background: transparent;
  color: var(--fg);
  cursor: pointer;
  font-size: 12px;
  text-align: left;
}

.context-menu button:hover {
  background: var(--accent);
  color: white;
}

