// 测试：Markdown 图片语法解析与替换
import * as assert from 'assert';
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { parseMarkdown } from '../src/markdown-parser';

suite('Markdown Parser', () => {
  let tmpDir: string;

  setup(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'image-flow-test-'));
  });

  teardown(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function createImage(name: string): string {
    // 创建一个最小的 PNG 文件
    const png = Buffer.from('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==', 'base64');
    const filePath = path.join(tmpDir, name);
    fs.writeFileSync(filePath, png);
    return filePath;
  }

  test('空内容（trim 后）应触发内容为空逻辑', () => {
    // parseMarkdown 本身不检查空内容，调用方负责
    // 此处验证解析不会崩溃
    const result = parseMarkdown('', tmpDir);
    assert.strictEqual(result.body, '');
    assert.strictEqual(result.references.length, 0);
  });

  test('无图片语法：正文原样返回', () => {
    const input = '一只猫在阳光下睡觉';
    const result = parseMarkdown(input, tmpDir);
    assert.strictEqual(result.body, '一只猫在阳光下睡觉');
    assert.strictEqual(result.references.length, 0);
  });

  test('普通路径：解析并替换', () => {
    createImage('cat.png');
    const input = '看这张 ![猫](cat.png) 图片';
    const result = parseMarkdown(input, tmpDir);
    assert.strictEqual(result.body, '看这张 [image1](cat) 图片');
    assert.strictEqual(result.references.length, 1);
    assert.strictEqual(result.references[0].index, 1);
    assert.ok(result.references[0].dataUri.startsWith('data:image/png;base64,'));
  });

  test('尖括号路径（含空格和括号）：正确解析', () => {
    createImage('my image (test).png');
    const input = '![图](<my image (test).png>) 描述';
    const result = parseMarkdown(input, tmpDir);
    assert.strictEqual(result.body, '[image1](my image (test)) 描述');
    assert.strictEqual(result.references.length, 1);
    assert.strictEqual(result.references[0].index, 1);
  });

  test('重复引用复用同一编号', () => {
    createImage('cat.png');
    const input = '![a](cat.png) 和 ![b](cat.png)';
    const result = parseMarkdown(input, tmpDir);
    // 两处引用用同一编号 1
    assert.strictEqual(result.body, '[image1](cat) 和 [image1](cat)');
    assert.strictEqual(result.references.length, 1);
    assert.strictEqual(result.references[0].index, 1);
  });

  test('多张参考图：编号顺序与首次出现一致', () => {
    createImage('cat.png');
    createImage('dog.jpg');
    const input = '![c](cat.png) 然后 ![d](dog.jpg)';
    const result = parseMarkdown(input, tmpDir);
    assert.strictEqual(result.body, '[image1](cat) 然后 [image2](dog)');
    assert.strictEqual(result.references.length, 2);
    assert.strictEqual(result.references[0].index, 1);
    assert.strictEqual(result.references[1].index, 2);
  });

  test('参考图读取失败：抛出错误并列出所有失败路径', () => {
    const input = '![a](nonexistent1.png) 和 ![b](nonexistent2.jpg)';
    assert.throws(() => {
      parseMarkdown(input, tmpDir);
    }, (err: Error) => {
      return err.message.includes('nonexistent1.png') && err.message.includes('nonexistent2.jpg');
    });
  });

  test('混合已存在和不存在图片：应全部失败', () => {
    createImage('cat.png');
    const input = '![a](cat.png) ![b](nonexistent.png)';
    assert.throws(() => {
      parseMarkdown(input, tmpDir);
    }, (err: Error) => {
      return err.message.includes('nonexistent.png');
    });
  });
});

// 测试：工具函数
import * as assert from 'assert';
import { isTransientHttpError, isTransientError, VIP_PIXEL_TABLE, formatDuration, dedupErrors, getExtFromUrl } from '../src/utils';

suite('Utils', () => {
  suite('Transient Error Detection', () => {
    test('HTTP 5xx 视为瞬时错误', () => {
      assert.strictEqual(isTransientHttpError(500), true);
      assert.strictEqual(isTransientHttpError(502), true);
      assert.strictEqual(isTransientHttpError(503), true);
      assert.strictEqual(isTransientHttpError(599), true);
    });

    test('HTTP 429 视为瞬时错误', () => {
      assert.strictEqual(isTransientHttpError(429), true);
    });

    test('HTTP 4xx（非 429）不是瞬时错误', () => {
      assert.strictEqual(isTransientHttpError(400), false);
      assert.strictEqual(isTransientHttpError(401), false);
      assert.strictEqual(isTransientHttpError(404), false);
    });

    test('HTTP 2xx 不是瞬时错误', () => {
      assert.strictEqual(isTransientHttpError(200), false);
    });

    test('fetch failed / abort / timeout 视为瞬时错误', () => {
      assert.strictEqual(isTransientError(new Error('fetch failed')), true);
      assert.strictEqual(isTransientError(new Error('The operation was aborted')), true);
      assert.strictEqual(isTransientError(new Error('Request timed out')), true);
    });

    test('普通 Error 不是瞬时错误', () => {
      assert.strictEqual(isTransientError(new Error('Something went wrong')), false);
    });

    test('格式错误不是瞬时错误', () => {
      assert.strictEqual(isTransientError(new Error('查询接口返回格式异常')), false);
    });

    test('null/undefined 不是瞬时错误', () => {
      assert.strictEqual(isTransientError(null), false);
      assert.strictEqual(isTransientError(undefined), false);
    });
  });

  suite('VIP Pixel Table', () => {
    test('1:1 分辨率', () => {
      assert.strictEqual(VIP_PIXEL_TABLE['1:1']['1K'], '1024x1024');
      assert.strictEqual(VIP_PIXEL_TABLE['1:1']['2K'], '2048x2048');
      assert.strictEqual(VIP_PIXEL_TABLE['1:1']['4K'], '2880x2880');
    });

    test('3:4 分辨率', () => {
      assert.strictEqual(VIP_PIXEL_TABLE['3:4']['1K'], '864x1152');
      assert.strictEqual(VIP_PIXEL_TABLE['3:4']['4K'], '2304x3072');
    });

    test('16:9 4K 符合约束（总像素 ≤ 8,294,400）', () => {
      const [w, h] = VIP_PIXEL_TABLE['16:9']['4K'].split('x').map(Number);
      assert.ok(w * h <= 8_294_400);
      assert.ok(w <= 3840 && h <= 3840);
      assert.strictEqual(w % 16, 0);
      assert.strictEqual(h % 16, 0);
    });

    test('9:16 分辨率', () => {
      assert.strictEqual(VIP_PIXEL_TABLE['9:16']['1K'], '768x1344');
      assert.strictEqual(VIP_PIXEL_TABLE['9:16']['2K'], '1536x2688');
    });
  });

  suite('formatDuration', () => {
    test('小于一小时显示 mm:ss', () => {
      assert.strictEqual(formatDuration(0), '00:00');
      assert.strictEqual(formatDuration(65_000), '01:05');
      assert.strictEqual(formatDuration(600_000), '10:00');
      assert.strictEqual(formatDuration(3_599_000), '59:59');
    });

    test('超过一小时显示 h:mm:ss', () => {
      assert.strictEqual(formatDuration(3_600_000), '1:00:00');
      assert.strictEqual(formatDuration(3_665_000), '1:01:05');
    });
  });

  suite('dedupErrors', () => {
    test('去重保留顺序', () => {
      const result = dedupErrors(['a', 'b', 'a', 'c', 'b']);
      assert.strictEqual(result, 'a\nb\nc');
    });

    test('过滤空字符串', () => {
      const result = dedupErrors(['a', '', 'b', '']);
      assert.strictEqual(result, 'a\nb');
    });

    test('空数组返回空字符串', () => {
      assert.strictEqual(dedupErrors([]), '');
    });
  });

  suite('getExtFromUrl', () => {
    test('标准 URL 提取扩展名', () => {
      assert.strictEqual(getExtFromUrl('https://example.com/image.png'), 'png');
      assert.strictEqual(getExtFromUrl('https://example.com/photo.jpg?size=large'), 'jpg');
      assert.strictEqual(getExtFromUrl('https://example.com/img.webp'), 'webp');
    });

    test('非图片扩展名回退 png', () => {
      assert.strictEqual(getExtFromUrl('https://example.com/video.mp4'), 'png');
      assert.strictEqual(getExtFromUrl('https://example.com/file.pdf'), 'png');
    });
  });

  suite('Aggregate Progress Calculation', () => {
    // 模拟 calcProgress 逻辑
    function calcProgress(jobs: Array<{ status: string; progress?: number }>): number {
      if (jobs.length === 0) { return 0; }
      let total = 0;
      for (const j of jobs) {
        if (j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation') {
          total += 100;
        } else if (j.status === 'running') {
          total += j.progress ?? 0;
        }
        // submitting → 0
      }
      return Math.round(total / jobs.length);
    }

    test('全部 submitting → 0%', () => {
      const jobs = [
        { status: 'submitting' },
        { status: 'submitting' },
      ];
      assert.strictEqual(calcProgress(jobs), 0);
    });

    test('混合态：1 running(50%) + 1 submitting → 25%', () => {
      const jobs = [
        { status: 'running', progress: 50 },
        { status: 'submitting' },
      ];
      assert.strictEqual(calcProgress(jobs), 25);
    });

    test('全部终结 → 100%', () => {
      const jobs = [
        { status: 'succeeded' },
        { status: 'failed' },
        { status: 'violation' },
      ];
      assert.strictEqual(calcProgress(jobs), 100);
    });

    test('部分终结：2 succeeded + 1 running(60%) → (200+60)/3 ≈ 87%', () => {
      const jobs = [
        { status: 'succeeded' },
        { status: 'succeeded' },
        { status: 'running', progress: 60 },
      ];
      assert.strictEqual(calcProgress(jobs), 87);
    });

    test('空 jobs → 0%', () => {
      assert.strictEqual(calcProgress([]), 0);
    });
  });
});

// 测试：预览请求组装
import * as assert from 'assert';
import { buildPreview } from '../src/preview';

suite('Preview', () => {
  test('预览文本包含四段：prompt、URL、参数JSON、参考图概览', () => {
    const result = buildPreview(
      'nano-banana-2',
      '3:4',
      '1K',
      'https://grsai.dakka.com.cn',
      '一只猫',
      [],
      [],
    );

    assert.ok(result.includes('一只猫'), '应包含 prompt');
    assert.ok(result.includes('POST https://grsai.dakka.com.cn/v1/api/generate'), '应包含请求地址');
    assert.ok(result.includes('"model"'), '应包含参数 JSON');
    assert.ok(result.includes('"replyType"'), '应包含 replyType');
    assert.ok(result.includes('---'), '应有分隔符');
  });

  test('无参考图时显示「无参考图」', () => {
    const result = buildPreview(
      'nano-banana-2', '1:1', '1K', 'https://grsai.dakka.com.cn',
      'prompt', [], [],
    );
    assert.ok(result.includes('无参考图'));
  });

  test('有参考图时显示概览', () => {
    const uris = ['data:image/png;base64,abc123def456'];
    const names = ['cat.png'];
    const result = buildPreview(
      'nano-banana-2', '1:1', '1K', 'https://grsai.dakka.com.cn',
      'prompt', uris, names,
    );
    assert.ok(result.includes('image1: data:image/png;base64,abc123def456'));
    assert.ok(result.includes('字符'));
  });

  test('剔除 prompt 和 images 字段：请求参数不包含 prompt', () => {
    const result = buildPreview(
      'gpt-image-2', '16:9', '2K', 'https://grsai.dakka.com.cn',
      'a long prompt about cats', [], [],
    );
    // JSON 部分不应包含 prompt（注意：prompt 在第一段，不在 JSON 里）
    const sections = result.split('\n\n---\n\n');
    const paramsSection = sections[2]; // 第三段是 JSON
    assert.ok(!paramsSection.includes('"prompt"'), 'JSON 参数段不应包含 prompt 字段');
    assert.ok(!paramsSection.includes('"images"'), 'JSON 参数段不应包含 images 字段');
  });

  test('nano-banana 系列包含 aspectRatio 和 imageSize', () => {
    const result = buildPreview(
      'nano-banana-pro', '4:3', '2K', 'https://grsai.dakka.com.cn',
      'test', [], [],
    );
    const sections = result.split('\n\n---\n\n');
    const params = sections[2];
    assert.ok(params.includes('"aspectRatio"'));
    assert.ok(params.includes('"imageSize"'));
  });

  test('gpt-image-2 包含 aspectRatio 但不含 imageSize', () => {
    const result = buildPreview(
      'gpt-image-2', '16:9', '2K', 'https://grsai.dakka.com.cn',
      'test', [], [],
    );
    const sections = result.split('\n\n---\n\n');
    const params = sections[2];
    assert.ok(params.includes('"aspectRatio"'));
    assert.ok(!params.includes('"imageSize"'));
  });

  test('gpt-image-2-vip 使用像素值作为 aspectRatio', () => {
    const result = buildPreview(
      'gpt-image-2-vip', '3:4', '2K', 'https://grsai.dakka.com.cn',
      'test', [], [],
    );
    const sections = result.split('\n\n---\n\n');
    const params = sections[2];
    assert.ok(params.includes('1728x2304'), '应包含像素值 1728x2304');
  });

  test('超长 data URI 截断为 48 字符 + …', () => {
    const longUri = 'data:image/png;base64,' + 'a'.repeat(100);
    const result = buildPreview(
      'nano-banana-2', '1:1', '1K', 'https://grsai.dakka.com.cn',
      'test', [longUri], ['long.png'],
    );
    const sections = result.split('\n\n---\n\n');
    const refs = sections[3];
    // 应出现 "…" 表示截断
    assert.ok(refs.includes('…'), `应包含截断符号，参考图内容: ${refs}`);
    // 总长度标识应显示
    assert.ok(refs.includes('字符'));
  });
});

// 测试运行器
import * as path from 'path';
import { runTests } from '@vscode/test-cli';

async function main(): Promise<void> {
  try {
    const extensionDevelopmentPath = path.resolve(__dirname, '..', '..');
    const extensionTestsPath = path.resolve(__dirname);

    await runTests({
      extensionDevelopmentPath,
      extensionTestsPath,
      launchArgs: ['--disable-extensions'],
    });
  } catch (err) {
    console.error('Failed to run tests:', err);
    process.exit(1);
  }
}

main();

